// n8n Code node (JavaScript)

// 🔧 Change this to whatever transaction type you want to filter
const TARGET_TYPE = "no_split_trial";

const inputItem = $input.first().json;
const transactions = inputItem.body?.transactions || [];

// Filter transactions by target type
const filteredTransactions = transactions.filter(
  transaction => transaction.type === TARGET_TYPE
);

// If none found, return indicator
if (filteredTransactions.length === 0) {
  return [
    {
      json: {
        noMatchingTransactions: true,
        filteredType: TARGET_TYPE
      }
    }
  ];
}

// Otherwise return each matching transaction as separate item
return filteredTransactions.map(transaction => ({
  json: transaction
}));

// n8n Code node (JavaScript)

// 🔧 Change this to the word you want to search for
const SEARCH_WORD = "trial";

const inputItem = $input.first().json;
const transactions = Array.isArray(inputItem.body?.transactions)
  ? inputItem.body.transactions
  : [];

// Normalize search word for case-insensitive matching
const normalizedSearch = SEARCH_WORD.toLowerCase();

// Filter transactions that contain the word in ANY field
const filteredTransactions = transactions.filter(transaction => {
  if (!transaction || typeof transaction !== "object") return false;

  return Object.values(transaction).some(value => {
    if (value === null || value === undefined) return false;

    return String(value).toLowerCase().includes(normalizedSearch);
  });
});

// If none found, return indicator
if (filteredTransactions.length === 0) {
  return [
    {
      json: {
        noMatchingTransactions: true,
        searchWord: SEARCH_WORD,
      },
    },
  ];
}

// Return each matching transaction as separate item
return filteredTransactions.map(transaction => ({
  json: transaction,
}));

