const crypto = require('crypto');

// --- Your credentials (store these in n8n credentials, not hardcoded) ---
const keyId = 'your-key-id';
const secret = 'your-secret';

// --- Request details (match what the HTTP Request node will send) ---
const method = 'POST';
const path = '/api/payments/v1/bot/search';
const body = { email: 'user@example.com' };

// --- Step 1: Timestamp + Nonce ---
const timestamp = String(Math.floor(Date.now() / 1000));
const nonce = crypto.randomBytes(16).toString('hex');

// --- Step 2: Sort keys and hash the body ---
function sortKeys(obj) {
  const sorted = {};
  for (const key of Object.keys(obj).sort()) {
    const val = obj[key];
    if (val && typeof val === 'object' && !Array.isArray(val)) {
      sorted[key] = sortKeys(val);
    } else {
      sorted[key] = val;
    }
  }
  return sorted;
}

const sortedBody = JSON.stringify(sortKeys(body));
const bodyHash = crypto.createHash('sha256').update(sortedBody, 'utf8').digest('hex');

// --- Step 3: Build canonical string ---
const canonical = `${method}\n${path}\n${timestamp}\n${nonce}\n${bodyHash}`;

// --- Step 4: Sign ---
const signature = crypto.createHmac('sha256', secret).update(canonical, 'utf8').digest('hex');

// --- Step 5: Output headers for the HTTP Request node ---
return [{
  json: {
    headers: {
      'X-Timestamp': timestamp,
      'X-Nonce': nonce,
      'X-Key-Id': keyId,
